#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Entities;

using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.instakillByWind)]
    public class InstakillByWind : EntityBehaviourDefinition, IBeBlownBehaviour
    {
        public InstakillByWind(string nsp, string name) : base(nsp, name)
        {
        }

        void IBeBlownBehaviour.BeBlown(Entity entity, Entity source)
        {
            entity.Die(new DamageEffectList(VanillaDamageEffects.INSTA_KILL), source);
        }
    }
}
